// Load OSM buildings
await db.loadOsmFromOverpassApi({
  queryArea: { geocodeArea: 'New York', areas: ['Financial District'] },
  outputTableName: 'osm',
  autoLoadLayers: {
    coordinateFormat: 'EPSG:3395',
    layers: ['surface', 'buildings'],
    dropOsmTable: true,
  },
});

// Load incident data
await db.loadCsv({
  csvFileUrl: '/data/incidents.csv',
  outputTableName: 'incidents',
  geometryColumns: {
    latColumnName: 'latitude',
    longColumnName: 'longitude',
    coordinateFormat: 'EPSG:3395',
  },
});

// Create heatmap of incidents
await db.buildHeatmap({
  tableJoinName: 'incidents',
  outputTableName: 'incident_heatmap',
  nearDistance: 300,
  grid: { rows: 20, columns: 20 },
  groupBy: {
    selectColumns: [{
      tableName: 'incidents',
      column: 'severity',
      aggregateFn: 'sum',
      aggregateFnResultColumnName: 'total_severity',
    }],
  },
});

// Render
const canvas = document.querySelector("canvas")!;
const map = new AutkMap(canvas);
await map.init();

// Load layers
const buildings = await db.getLayer('osm_buildings');
map.loadGeoJsonLayer('buildings', buildings, LayerType.AUTK_OSM_BUILDINGS);

const heatmap = await db.getLayer('incident_heatmap');
map.loadGeoTiffLayer('heatmap', heatmap, LayerType.AUTK_RASTER);

// Color buildings by height
map.updateRenderInfoProperty('buildings', 'colorMapInterpolator', 
  ColorMapInterpolator.SEQUENTIAL_BLUES);
map.updateGeoJsonLayerThematic(
  'buildings',
  buildings,
  (f) => f.properties?.height ?? 0,
  true // group by building ID
);

map.draw();
```

### **Compute → Update → Thematic Pattern:**

```typescript
import { geojsonCompute } from 'autk-compute';

// Get data
const geojson = await db.getLayer('buildings');

// Compute new property (volume = area * floors)
const enriched = await geojsonCompute.computeFunctionIntoProperties({
  geojson,
  variableMapping: {
    area: 'properties.area',
    floors: 'properties.floors',
  },
  outputColumnName: 'volume',
  wglsFunction: 'return area * floors;',
});

// Update database
await db.updateTable({
  tableName: 'buildings',
  data: enriched,
  strategy: 'replace',
});

// Thematic map by computed value
const updated = await db.getLayer('buildings');
map.updateRenderInfoProperty('buildings', 'colorMapInterpolator', 
  ColorMapInterpolator.SEQUENTIAL_BLUES);
map.updateGeoJsonLayerThematic(
  'buildings',
  updated,
  (f) => f.properties?.compute?.volume ?? 0,
  true
);
```

### **Linked Views Pattern:**

```typescript
import { Scatterplot, PlotEvent } from 'autk-plot';
import { MapEvent } from 'autk-map';

// Enable picking on map
map.updateRenderInfoProperty('buildings', 'isPick', true);
map.updateRenderInfoProperty('buildings', 'isColorMap', true);

// Create chart
const geojson = await db.getLayer('buildings');
const chart = new Scatterplot({
  div: document.querySelector('#chart') as HTMLElement,
  data: geojson,
  labels: { axis: ['area', 'height'], title: 'Building Analysis' },
  width: 600,
  height: 400,
});

// Map → Chart: clicking building highlights it in chart
map.mapEvents.on(MapEvent.PICK, (selectedIds) => {
  chart.setHighlightedIds(selectedIds);
});

// Chart → Map: brushing chart colors buildings
chart.plotEvents.on(PlotEvent.BRUSH, (selectedIds) => {
  chart.setHighlightedIds(selectedIds);
  map.updateGeoJsonLayerThematic(
    'buildings',
    geojson,
    (_f, i) => selectedIds.includes(i) ? 1.0 : 0.0
  );
});
```

### **Minimal End-to-End Example (from docs):**

```typescript
import { SpatialDb } from "autk-db";
import { AutkMap, LayerType } from "autk-map";

async function main() {
  const canvas = document.querySelector("canvas")!;
  const db = new SpatialDb();
  await db.init();

  await db.loadOsmFromOverpassApi({
    queryArea: { geocodeArea: "New York", areas: ["Battery Park City", "Financial District"] },
    outputTableName: "osm",
    autoLoadLayers: {
      coordinateFormat: "EPSG:3395",
      layers: ["surface", "parks", "water", "roads", "buildings"],
      dropOsmTable: true,
    },
    onProgress: (phase) => console.log(phase),
  });

  const map = new AutkMap(canvas);
  await map.init();

  for (const layer of db.getLayerTables()) {
    const geojson = await db.getLayer(layer.name);
    map.loadGeoJsonLayer(layer.name, geojson, layer.type as LayerType);
  }

  map.draw();
}

main();
```

---

## Key Concepts Summary

**Tables vs Layers:**
- **Tables** are named data containers in DuckDB
- **Layers** are tables with a geometry column that can be rendered by autk-map

**Data Flow:**
1. Load operations create tables in DuckDB (data stays in DB, not in JS memory)
2. Query/analysis operations transform data inside DuckDB
3. Getter operations move data from DuckDB to JavaScript memory
4. Map/chart operations render the data

**Coordinate Systems:**
- Use `'EPSG:3395'` (World Mercator) for most city-scale visualizations
- This is the format expected by autk-map

**Browser Requirements:**
- WebGPU: Chrome 113+, Edge 113+, Safari 18+ (for rendering)
- Modern browser: Any (for database and charts)

